// Pre-flight validation: check env vars, profile files, config.json
const fs = require('fs');
const errors = [];

const projectDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '').replace(/\\/g, '/');
const profile = $env.JOBS_FUNNEL_PROFILE || '';
const table = $env.JOBS_FUNNEL_TABLE || '';

// Required env vars
if (!projectDir) errors.push('JOBS_FUNNEL_PROJECT_DIR not set');
if (!profile) errors.push('JOBS_FUNNEL_PROFILE not set');
if (!table) errors.push('JOBS_FUNNEL_TABLE not set');

// Profile directory structure
if (projectDir && profile) {
  const profileDir = projectDir + '/profiles/' + profile;
  if (!fs.existsSync(profileDir)) {
    errors.push(`Profile dir not found: ${profileDir}`);
  } else {
    if (!fs.existsSync(profileDir + '/search.json')) errors.push('Missing: search.json');
    if (!fs.existsSync(profileDir + '/filter_prompt.md')) errors.push('Missing: filter_prompt.md');
    const cvsDir = profileDir + '/cvs';
    if (!fs.existsSync(cvsDir)) {
      errors.push('Missing: cvs/ directory');
    } else {
      const cvFiles = fs.readdirSync(cvsDir).filter(f => f.endsWith('.html'));
      if (cvFiles.length === 0) errors.push('No .html files in cvs/ directory');
    }
  }
}

// config.json
if (projectDir) {
  try {
    const config = JSON.parse(fs.readFileSync(projectDir + '/config.json', 'utf-8'));
    const required = ['batch_size', 'dedup_cap', 'description_max_chars'];
    for (const key of required) {
      if (config[key] === undefined) errors.push(`config.json missing key: ${key}`);
    }
  } catch (e) {
    errors.push('config.json not found or invalid JSON');
  }
}

if (errors.length > 0) {
  throw new Error('Pre-flight check failed:\n- ' + errors.join('\n- '));
}

return [{ json: { _preflight: 'ok', profile, table } }];

// Arbeitnow: paginate up to 10 pages, relaxed client-side filters
const fs = require('fs');
const projectDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/');
const config = JSON.parse(fs.readFileSync(projectDir + '/config.json', 'utf-8'));
const profileDir = projectDir + '/profiles/' + ($env.JOBS_FUNNEL_PROFILE);
const search = JSON.parse(fs.readFileSync(profileDir + '/search.json', 'utf-8'));

const MAX_PAGES = config.an_max_pages || 10;
const DELAY_MS = config.an_delay_ms || 5000;
const MAX_RETRIES = config.api_max_retries || 2;
const RETRY_DELAY = config.api_retry_delay_ms || 1000;
const cutoff = Date.now() - (config.an_days_back || 30) * 24 * 60 * 60 * 1000;

// Retry with exponential backoff; skip retries for 4xx (permanent errors)
async function fetchWithRetry(opts) {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await this.helpers.httpRequest(opts);
    } catch (e) {
      const msg = e.message || String(e);
      const is4xx = /\b4\d{2}\b/.test(msg) || msg.includes('Bad Request') || msg.includes('Not Found');
      if (is4xx || attempt === MAX_RETRIES) throw e;
      await new Promise(r => setTimeout(r, RETRY_DELAY * Math.pow(2, attempt)));
    }
  }
}

const titleKw = search.an_title_keywords || [];
const tagKw = search.an_tag_keywords || [];
const locKw = search.an_location_keywords || [];
const negKw = search.an_negative_keywords || [];
const engWords = ['the','and','you','we','team','experience','requirements','about','our','will','work','join','role','position'];

function isLikelyEnglish(desc) {
  const sample = (desc || '').substring(0, 500).toLowerCase();
  const hits = engWords.filter(w => sample.includes(w)).length;
  return hits >= 3;
}

const allJobs = [];
const seen = new Set();
const errors = [];
var lastPage = 0;
const CB_THRESHOLD = config.circuit_breaker_threshold ?? 0.8;
const CB_MIN = config.circuit_breaker_min_requests ?? 5;
let totalRequests = 0;
let failedRequests = 0;
let circuitBroken = false;

for (let page = 1; page <= MAX_PAGES; page++) {
  if (page > 1) await new Promise(r => setTimeout(r, DELAY_MS));
  if (totalRequests >= CB_MIN && failedRequests / totalRequests >= CB_THRESHOLD) {
    circuitBroken = true;
    break;
  }
  lastPage = page;
  let body;
  try {
    body = await fetchWithRetry.call(this, { method: 'GET', url: `https://www.arbeitnow.com/api/job-board-api?page=${page}`, json: true });
    totalRequests++;
  } catch (e) {
    totalRequests++;
    failedRequests++;
    errors.push({ page, error: e.message || String(e) });
    continue; // Try next page instead of breaking
  }
  const data = body.data || [];
  if (data.length === 0) break;

  let allOld = true;
  for (const job of data) {
    const created = new Date(job.created_at * 1000 || job.created_at).getTime();
    if (created > cutoff) allOld = false;

    const t = (job.title || '').toLowerCase();
    const l = (job.location || '').toLowerCase();
    const tags = (job.tags || []).map(t => t.toLowerCase());
    const titleMatch = titleKw.some(k => t.includes(k));
    const tagMatch = tagKw.some(k => tags.includes(k));
    const locMatch = locKw.some(k => l.includes(k)) || job.remote;
    const negMatch = negKw.some(k => t.includes(k));

    if (!negMatch && (titleMatch || tagMatch || locMatch) && created > cutoff) {
      const key = job.slug || job.url || job.title;
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push(job);
      }
    }
  }
  if (allOld) break;
  const maxPage = body.meta?.last_page || MAX_PAGES;
  if (page >= maxPage) break;
}

// Fail visibly if ALL requests errored
if (allJobs.length === 0 && errors.length > 0) {
  throw new Error(`AN: all ${errors.length} page requests failed after retries. First error: ${errors[0].error}`);
}

if (allJobs.length === 0) return [];

function parseSalary(job) {
  let min = job.salary_min || null;
  let max = job.salary_max || null;
  let currency = job.salary_currency || null;
  if (!min && job.salary) {
    const nums = String(job.salary).replace(/[.,]/g, '').match(/\d+/g);
    if (nums && nums.length >= 2) { min = Number(nums[0]); max = Number(nums[1]); }
    else if (nums && nums.length === 1) { min = Number(nums[0]); }
    if (!currency && /eur|€/i.test(job.salary)) currency = 'EUR';
    if (!currency && /usd|\$/i.test(job.salary)) currency = 'USD';
    if (!currency && /chf/i.test(job.salary)) currency = 'CHF';
    if (!currency && /gbp|£/i.test(job.salary)) currency = 'GBP';
  }
  return { salary_min: min, salary_max: max, salary_currency: currency || (min ? 'EUR' : null) };
}

const _crawlMeta = {
  source: 'arbeitnow',
  pages_fetched: lastPage,
  total_results: allJobs.length,
  fetch_errors: errors.length,
  errors: errors.slice(0, 10),
  circuit_broken: circuitBroken,
  circuit_breaker_stats: { total: totalRequests, failed: failedRequests },
};

const mapped = allJobs.map(j => {
  const desc = (j.description || '').substring(0, config.description_max_chars || 5000);
  const sal = parseSalary(j);
  return { json: {
    source: 'arbeitnow',
    external_id: j.slug || '',
    url: j.url || `https://www.arbeitnow.com/view/${j.slug}`,
    title: j.title || '',
    company: j.company_name || '',
    location: j.location || '',
    description: desc,
    description_quality: (desc.length > 100) ? 'good' : 'poor',
    tags: j.tags || [],
    remote: j.remote || false,
    likely_english: isLikelyEnglish(desc),
    _rawApiData: j,
    salary_min: sal.salary_min,
    salary_max: sal.salary_max,
    salary_currency: sal.salary_currency,
    start_date: null,
    posted_at: j.created_at ? new Date(j.created_at * 1000 || j.created_at).toISOString() : null,
  }};
});
if (mapped.length > 0) mapped[0].json._crawlMeta = _crawlMeta;
return mapped;

// Arbeitsagentur: run multiple server-side filtered searches + fetch full descriptions
const fs = require('fs');
const projectDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/');
const config = JSON.parse(fs.readFileSync(projectDir + '/config.json', 'utf-8'));
const profileDir = projectDir + '/profiles/' + ($env.JOBS_FUNNEL_PROFILE);
const search = JSON.parse(fs.readFileSync(profileDir + '/search.json', 'utf-8'));

const BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobs';
const HEADERS = { 'X-API-Key': 'jobboerse-jobsuche', 'User-Agent': 'Mozilla/5.0', 'Accept': 'application/json' };
const MAX_RETRIES = config.api_max_retries || 2;
const RETRY_DELAY = config.api_retry_delay_ms || 1000;

// Retry with exponential backoff; skip retries for 4xx (permanent errors)
async function fetchWithRetry(opts) {
  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
    try {
      return await this.helpers.httpRequest(opts);
    } catch (e) {
      const msg = e.message || String(e);
      const is4xx = /\b4\d{2}\b/.test(msg) || msg.includes('Bad Request') || msg.includes('Not Found');
      if (is4xx || attempt === MAX_RETRIES) throw e;
      await new Promise(r => setTimeout(r, RETRY_DELAY * Math.pow(2, attempt)));
    }
  }
}

const searches = search.aa_searches || [];
// Support multiple locations: aa_locations array or legacy aa_location string
const locations = search.aa_locations || [
  { location: search.aa_location, radius_km: search.aa_radius_km }
];

const seenIds = new Set();
const jobs = [];
const errors = [];
const MAX_PAGES = config.aa_max_pages || 3;
const CB_THRESHOLD = config.circuit_breaker_threshold ?? 0.8;
const CB_MIN = config.circuit_breaker_min_requests ?? 5;
let searchTotal = 0;
let searchFailed = 0;
let circuitBroken = false;

for (const loc of locations) {
  const locParams = `wo=${encodeURIComponent(loc.location)}&umkreis=${loc.radius_km || 200}&veroeffentlichtseit=30&pav=false&zeitarbeit=false&size=100`;
  for (let i = 0; i < searches.length; i++) {
    for (let page = 1; page <= MAX_PAGES; page++) {
      if (searchTotal >= CB_MIN && searchFailed / searchTotal >= CB_THRESHOLD) {
        circuitBroken = true;
        break;
      }
      const url = `${BASE}?was=${encodeURIComponent(searches[i])}&${locParams}&page=${page}`;
      let body;
      try {
        const raw = await fetchWithRetry.call(this, { method: 'GET', url, headers: HEADERS });
        body = typeof raw === 'string' ? JSON.parse(raw) : raw;
        searchTotal++;
      } catch (e) {
        searchTotal++;
        searchFailed++;
        errors.push({ location: loc.location, search: searches[i], page, error: e.message || String(e) });
        continue;
      }
      const results = body.stellenangebote || [];
      if (results.length === 0) break;
      for (const s of results) {
        const id = s.refnr || s.titel;
        if (!seenIds.has(id)) { seenIds.add(id); jobs.push(s); }
      }
      const maxPage = body.maxErgebnisse ? Math.ceil(body.maxErgebnisse / 100) : 1;
      if (page >= maxPage) break;
    }
    if (circuitBroken) break;
  }
  if (circuitBroken) break;
}

// Fail visibly if ALL requests errored (not just "no jobs found")
if (jobs.length === 0 && errors.length > 0) {
  throw new Error(`AA: all ${errors.length} requests failed after retries. First error: ${errors[0].error}`);
}

if (jobs.length === 0) return [];

// Fetch full descriptions from employer pages (externeUrl)
function decodeEntities(text) {
  return text
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&apos;/g, "'")
    .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(Number(n)))
    .replace(/&#x([0-9a-fA-F]+);/g, (_, h) => String.fromCharCode(parseInt(h, 16)));
}

function extractDescription(html) {
  const str = String(html);

  // Try JSON-LD first (structured data, cleanest source)
  const jsonLdMatch = str.match(/<script[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi);
  if (jsonLdMatch) {
    for (const block of jsonLdMatch) {
      try {
        const content = block.replace(/<\/?script[^>]*>/gi, '');
        const data = JSON.parse(content);
        // Could be a single object or array
        const items = Array.isArray(data) ? data : [data];
        for (const item of items) {
          if (item['@type'] === 'JobPosting' && item.description) {
            // Description may be HTML, strip it
            let desc = item.description.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
            desc = decodeEntities(desc);
            // Also grab benefits/qualifications if available
            const extras = [item.qualifications, item.responsibilities, item.jobBenefits]
              .filter(Boolean).map(s => String(s).replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim());
            if (extras.length) desc += ' ' + extras.join(' ');
            if (desc.length > 100) return desc;
          }
        }
      } catch (e) { /* invalid JSON-LD, try next block */ }
    }
  }

  // Fallback: strip script/style blocks, then strip tags
  let text = str
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<nav[\s\S]*?<\/nav>/gi, ' ')
    .replace(/<header[\s\S]*?<\/header>/gi, ' ')
    .replace(/<footer[\s\S]*?<\/footer>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  text = decodeEntities(text);
  return text.length > 100 ? text : null;
}

function checkDescriptionQuality(desc) {
  if (!desc || desc.length < 50) return 'empty';

  const lower = desc.toLowerCase();
  const len = desc.length;

  // Junk patterns — cookie notices, login walls, error pages
  const junkPatterns = [
    'cookie', 'datenschutz', 'privacy policy', 'accept all',
    'page not found', '404', 'access denied', 'forbidden',
    'javascript is required', 'enable javascript',
    'please log in', 'bitte melden sie sich an',
    'captcha', 'robot'
  ];
  const junkHits = junkPatterns.filter(p => lower.includes(p)).length;
  if (junkHits >= 2) return 'poor';

  // Job-related keywords — a real posting should have several
  const jobKeywords = [
    'aufgaben', 'anforderungen', 'profil', 'qualifikation',
    'responsibilities', 'requirements', 'experience', 'skills',
    'benefits', 'salary', 'gehalt', 'team', 'position',
    'bewerben', 'apply', 'stellenangebot', 'job', 'rolle',
    'arbeiten', 'work', 'develop', 'engineer', 'manage'
  ];
  const jobHits = jobKeywords.filter(k => lower.includes(k)).length;

  if (len < 200 && jobHits < 2) return 'poor';
  if (len >= 200 && jobHits >= 2) return 'good';
  if (len >= 500) return 'good';

  return 'poor';
}

const FETCH_DELAY = config.aa_fetch_delay_ms || 300;
const MAX_FETCHES = config.aa_max_fetches || 200;
const DESC_CB_MIN = 10;
let fetchCount = 0;
let descFailCount = 0;
let descCircuitBroken = false;
const descFailUrls = [];
for (let i = 0; i < jobs.length && fetchCount < MAX_FETCHES; i++) {
  const extUrl = jobs[i].externeUrl;
  if (!extUrl) continue;
  if (fetchCount >= DESC_CB_MIN && descFailCount / fetchCount >= CB_THRESHOLD) {
    descCircuitBroken = true;
    break;
  }
  if (fetchCount > 0) await new Promise(r => setTimeout(r, FETCH_DELAY));
  fetchCount++;
  let success = false;
  // 1 retry for descriptions (nice-to-have)
  for (let attempt = 0; attempt <= 1 && !success; attempt++) {
    try {
      const html = await this.helpers.httpRequest({ method: 'GET', url: extUrl, encoding: 'utf-8', timeout: config.aa_fetch_timeout_ms || 5000 });
      const desc = extractDescription(html);
      if (desc) {
        jobs[i]._fullDesc = desc.substring(0, config.description_max_chars || 5000);
        jobs[i]._descriptionQuality = checkDescriptionQuality(jobs[i]._fullDesc);
      }
      success = true;
    } catch (e) {
      if (attempt === 1) {
        descFailCount++;
        descFailUrls.push(extUrl);
      } else {
        await new Promise(r => setTimeout(r, 500));
      }
    }
  }
}

const _crawlMeta = {
  source: 'arbeitsagentur',
  locations: locations.map(l => l.location),
  searches_run: searches.length * locations.length,
  total_results: jobs.length,
  fetch_errors: errors.length,
  errors: errors.slice(0, 10),
  descriptions_attempted: fetchCount,
  descriptions_failed: descFailCount,
  descriptions_failed_urls: descFailUrls.slice(0, 10),
  circuit_broken: circuitBroken || descCircuitBroken,
  circuit_breaker_stats: {
    search: { total: searchTotal, failed: searchFailed },
    descriptions: { total: fetchCount, failed: descFailCount },
  },
};

const mapped = jobs.map(j => {
  const company = typeof j.arbeitgeber === 'object' ? (j.arbeitgeber?.name || '') : (j.arbeitgeber || '');
  const location = j.arbeitsort?.ort || '';
  const region = j.arbeitsort?.region || '';
  const extUrl = j.externeUrl || '';
  const refUrl = j.refnr ? `https://www.arbeitsagentur.de/jobsuche/suche?id=${j.refnr}` : '';
  const url = extUrl || refUrl;
  const fallbackDesc = `${j.titel || ''} bei ${company} in ${location}${region ? ' (' + region + ')' : ''}. Beruf: ${j.beruf || ''}. Eintrittsdatum: ${j.eintrittsdatum || 'k.A.'}`;
  const desc = (j._fullDesc || fallbackDesc).substring(0, config.description_max_chars || 5000);
  return { json: {
    source: 'arbeitsagentur',
    external_id: j.refnr || '',
    url: url,
    title: j.titel || '',
    company: company,
    location: location,
    description: desc,
    description_quality: j._descriptionQuality || (j._fullDesc ? 'unknown' : 'empty'),
    tags: [],
    remote: false,
    likely_english: false,
    _rawApiData: j,
    start_date: j.eintrittsdatum || null,
    posted_at: null
  }};
});
if (mapped.length > 0) mapped[0].json._crawlMeta = _crawlMeta;
return mapped;

// Deduplicate merged results by normalized company+title
const all = $input.all().filter(i => i.json.url);
const seen = new Set();
const unique = [];

function normalize(s) {
  return (s || '')
    .toLowerCase()
    .trim()
    .replace(/\s+(gmbh|ag|se|kg|co|ltd|inc|ug|mbh|e\.v\.|ohg|gbr)\.?\s*$/i, '')
    .replace(/\s+/g, ' ')
    .replace(/[^\w\s]/g, '');
}

for (const item of all) {
  const job = item.json;
  const key = normalize(job.company) + '|' + normalize(job.title);
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(job);
  }
}

if (unique.length === 0) return [];
return unique.map(j => ({ json: j }));

// Filter out URLs already in Postgres — insert all new jobs, analyze phase handles batching
// Let this throw if upstream DB node failed — better than bypassing dedup
const seenRows = $('Dedup: Get Seen URLs').all();
const seenUrls = new Set(seenRows.map(r => r.json.url).filter(Boolean));

const jobs = $('Has Results?').all().filter(item => {
  const url = item.json?.url;
  return url && !seenUrls.has(url);
});

if (jobs.length === 0) return [];
return jobs;

// Build safe INSERT query for each job
const table = $env.JOBS_FUNNEL_TABLE;
// Proper SQL escaping: handles quotes, backslashes, null bytes
function sqlStr(s) {
  if (s === null || s === undefined) return 'NULL';
  return "'" + String(s).replace(/\\/g, '\\\\').replace(/'/g, "''").replace(/\0/g, '') + "'";
}

// Dollar-quoted JSONB literal: avoids double-encoding from sqlStr + ::jsonb cast
function jsonbLiteral(value) {
  const arr = Array.isArray(value) ? value : [];
  const json = JSON.stringify(arr);
  let tag = '$jb$';
  if (json.includes(tag)) tag = '$jb2$';
  return tag + json + tag + '::jsonb';
}

return $input.all().map(item => {
  const j = item.json;
  const postedAt = j.posted_at ? sqlStr(j.posted_at) : 'NULL';
  const descQuality = j.description_quality || 'unknown';
  const query = `INSERT INTO ${table} (url, title, company, location, description, description_quality, source, external_id, tags, remote, likely_english, salary_min, salary_max, salary_currency, start_date, posted_at) VALUES (${sqlStr(j.url)}, ${sqlStr(j.title)}, ${sqlStr(j.company)}, ${sqlStr(j.location)}, ${sqlStr((j.description || '').substring(0, 10000))}, ${sqlStr(descQuality)}, ${sqlStr(j.source)}, ${sqlStr(j.external_id)}, ${jsonbLiteral(j.tags)}, ${j.remote || false}, ${j.likely_english || false}, ${j.salary_min || 'NULL'}, ${j.salary_max || 'NULL'}, ${sqlStr(j.salary_currency || null)}, ${sqlStr(j.start_date || null)}, ${postedAt}) ON CONFLICT (url) DO NOTHING`;
  let combinedQuery = query;
  if (j._rawApiData) {
    const rawJson = JSON.stringify(j._rawApiData);
    let tag = '$rd$';
    if (rawJson.includes(tag)) tag = '$rd2$';
    combinedQuery += `; INSERT INTO job_raw_data (url, raw_json, source) VALUES (${sqlStr(j.url)}, ${tag}${rawJson}${tag}::jsonb, ${sqlStr(j.source)}) ON CONFLICT (url) DO NOTHING`;
  }
  return { json: { _insertQuery: combinedQuery } };
});

// Emit a single item to trigger the analyze phase, carrying crawl counts
let crawled = 0, inserted = 0;
try { crawled = $('Dedup Merge').all().length; } catch(e) {}
try { inserted = $('Dedup: Filter New').all().filter(i => !i.json._empty).length; } catch(e) {}
return [{ json: { _trigger: 'crawl_complete', _crawled: crawled, _inserted: inserted } }];

// Check if there are pending jobs — output flag when done
const items = $input.all().filter(i => i.json.id != null);
if (items.length === 0) return [{ json: { _done: true } }];
return items;

// Batch all pending jobs into groups of N, write each to a temp file
const fs = require('fs');
const config = JSON.parse(fs.readFileSync(
  ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/config.json', 'utf-8'
));
const BATCH_SIZE = config.batch_size || 8;
const all = $input.all();
const tmpDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/') + '/temp';

// Ensure temp dir exists (let it throw if it can't create)
fs.mkdirSync(tmpDir, { recursive: true });
// Clean old batch files (non-critical, silent on failure)
try {
  const oldFiles = fs.readdirSync(tmpDir).filter(f => f.startsWith('n8n_batch_'));
  for (const f of oldFiles) { try { fs.unlinkSync(tmpDir + '/' + f); } catch (e) {} }
} catch (e) {}

const batches = [];
for (let i = 0; i < all.length; i += BATCH_SIZE) {
  const chunk = all.slice(i, i + BATCH_SIZE);
  const batchJobs = chunk.map(item => ({
    title: item.json.title || '',
    company: item.json.company || '',
    location: item.json.location || '',
    description: (item.json.description || '').substring(0, 3000),
    tags: item.json.tags || [],
    url: item.json.url || '',
    remote: item.json.remote || false,
    source: item.json.source || '',
    salary_min: item.json.salary_min || null,
    salary_max: item.json.salary_max || null,
    salary_currency: item.json.salary_currency || null,
    start_date: item.json.start_date || null,
    _likely_english: item.json.likely_english || false
  }));
  const tmpPath = tmpDir + '/n8n_batch_' + Date.now() + '_' + i + '.json';
  fs.writeFileSync(tmpPath, JSON.stringify(batchJobs), 'utf-8');
  const originals = chunk.map(item => ({
    id: item.json.id,
    url: item.json.url,
    title: item.json.title,
    company: item.json.company,
    location: item.json.location,
    source: item.json.source
  }));
  batches.push({ json: { _tmpPath: tmpPath, _batchOriginals: originals, _batchSize: chunk.length } });
}
return batches;

// Unbatch: match each Claude response to its batch, then build UPDATE SQL
const table = $env.JOBS_FUNNEL_TABLE;
const batchItems = $('Batch Items').all();
const VALID_VARIANTS = ['software', 'data', 'fullstack', 'systems'];
const ERROR_KEYWORDS = ['parse error', 'incomplete', 'timed out', 'filter error', 'claude response parse'];

// Proper SQL escaping: handles quotes, backslashes, null bytes
function sqlStr(s) {
  if (s === null || s === undefined) return 'NULL';
  return "'" + String(s).replace(/\\/g, '\\\\').replace(/'/g, "''").replace(/\0/g, '') + "'";
}

// Dollar-quoted JSONB literal: avoids double-encoding from sqlStr + ::jsonb cast
function jsonbLiteral(value) {
  const arr = Array.isArray(value) ? value : [];
  const json = JSON.stringify(arr);
  let tag = '$jb$';
  if (json.includes(tag)) tag = '$jb2$';
  return tag + json + tag + '::jsonb';
}

// Derive error_code: prefer explicit field from filter.py, else classify from content
function classifyErrorCode(assessment) {
  if (assessment.error_code) return assessment.error_code;
  if ((assessment.priority_notes || '').includes('BATCH_PADDING')) return 'BATCH_PADDING';
  const reasoning = (assessment.reasoning || '').toLowerCase();
  if (reasoning.includes('timed out')) return 'TIMEOUT';
  const blockers = (assessment.hard_blockers || []).join(' ').toLowerCase();
  if (blockers.includes('parse error') || blockers.includes('claude response parse')) return 'PARSE_FAIL';
  if (blockers.includes('filter error')) return 'API_ERROR';
  return 'API_ERROR';
}

// Transition to 'dead' when retry budget exhausted, otherwise 'error'
const DEAD_STATUS_EXPR = "CASE WHEN retry_count + 1 >= 3 THEN 'dead' ELSE 'error' END";

const results = [];
for (let b = 0; b < $input.all().length; b++) {
  const item = $input.all()[b];
  const stdout = item.json.stdout || '[]';
  const originals = (batchItems[b] && batchItems[b].json._batchOriginals) || [];

  let assessments;
  try {
    assessments = JSON.parse(stdout);
    if (!Array.isArray(assessments)) assessments = [assessments];
  } catch (e) {
    for (const orig of originals) {
      results.push({ json: {
        _updateQuery: `UPDATE ${table} SET status = ${DEAD_STATUS_EXPR}, error = ${sqlStr('Failed to parse Claude response: ' + e.message)}, error_code = 'PARSE_FAIL', retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
    }
    continue;
  }

  for (let i = 0; i < originals.length; i++) {
    const orig = originals[i];
    const assessment = assessments[i];

    if (!assessment) {
      results.push({ json: {
        _updateQuery: `UPDATE ${table} SET status = ${DEAD_STATUS_EXPR}, error = 'No result returned for this job in batch response', error_code = 'NO_RESULT', retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
      continue;
    }

    const rawDecision = String(assessment.decision || 'SKIP').trim().toUpperCase();
    const decision = ['PASS', 'MAYBE', 'SKIP'].includes(rawDecision) ? rawDecision : 'SKIP';
    const score = Number(assessment.fit_score) || 0;

    // Detect batch padding (job was never evaluated by Claude)
    const isBatchPadding = (assessment.priority_notes || '').includes('BATCH_PADDING');

    // Detect fallback/error responses from filter.py
    const isErrorFallback = isBatchPadding || (score === 0 && (assessment.hard_blockers || []).some(b =>
      ERROR_KEYWORDS.some(kw => b.toLowerCase().includes(kw))
    ));

    if (isErrorFallback) {
      const errCode = classifyErrorCode(assessment);
      results.push({ json: {
        _updateQuery: `UPDATE ${table} SET status = ${DEAD_STATUS_EXPR}, error = ${sqlStr(assessment.reasoning || 'Fallback SKIP from failed Claude call')}, error_code = '${errCode}', retry_count = retry_count + 1 WHERE id = ${orig.id}`
      }});
      continue;
    }

    // Validate cv_variant
    const cvVariant = VALID_VARIANTS.includes(assessment.cv_variant) ? assessment.cv_variant : 'software';

    // Extracted fields (best-effort, may be null)
    const empType = assessment.employment_type || null;
    const senLevel = assessment.seniority_level || null;
    const startDate = assessment.start_date || null;
    const exSalMin = assessment.extracted_salary_min || null;
    const exSalMax = assessment.extracted_salary_max || null;
    const exSalCur = assessment.extracted_salary_currency || null;

    // Conditional salary: only update if DB has no salary (don't overwrite API-provided values)
    const salaryClause = exSalMin
      ? `, salary_min = CASE WHEN salary_min IS NULL THEN ${Number(exSalMin)} ELSE salary_min END, salary_max = CASE WHEN salary_max IS NULL THEN ${exSalMax ? Number(exSalMax) : 'NULL'} ELSE salary_max END, salary_currency = CASE WHEN salary_currency IS NULL OR salary_currency = 'EUR' THEN ${sqlStr(exSalCur || 'EUR')} ELSE salary_currency END`
      : '';

    results.push({ json: {
      _updateQuery: `UPDATE ${table} SET status = 'analyzed', analyzed_at = NOW(), error = NULL, error_code = NULL, retry_count = 0, fit_score = ${score}, decision = '${decision}', cv_variant = '${cvVariant}', hard_blockers = ${jsonbLiteral(assessment.hard_blockers)}, soft_gaps = ${jsonbLiteral(assessment.soft_gaps)}, strong_matches = ${jsonbLiteral(assessment.strong_matches)}, reasoning = ${sqlStr(assessment.reasoning || '')}, priority_notes = ${sqlStr(assessment.priority_notes || null)}, employment_type = ${sqlStr(empType)}, seniority_level = ${sqlStr(senLevel)}, start_date = COALESCE(start_date, ${sqlStr(startDate)})${salaryClause} WHERE id = ${orig.id}`
    }});
  }
}
return results;

// Prep semantic duplicate detection: collect newly analyzed jobs + existing jobs,
// write a temp file for dedup_semantic.py to process.
const fs = require('fs');
const table = $env.JOBS_FUNNEL_TABLE;
const projectDir = ($env.JOBS_FUNNEL_PROJECT_DIR || '.').replace(/\\/g, '/');
const tmpDir = projectDir + '/temp';

// Collect newly analyzed job IDs from the batch originals (via Parse + Prep Update)
// We reference the Batch Items node which has _batchOriginals with id/title/company/location
const batchItems = $('Batch Items').all();
const parseResults = $('Parse + Prep Update').all();

const newJobs = [];
for (let b = 0; b < batchItems.length; b++) {
  const originals = (batchItems[b].json._batchOriginals) || [];
  const updateQuery = (parseResults[b] && parseResults[b].json._updateQuery) || '';
  for (let i = 0; i < originals.length; i++) {
    // Only include successfully analyzed jobs (query contains status = 'analyzed')
    if (updateQuery.includes("status = 'analyzed'")) {
      newJobs.push({
        id: originals[i].id,
        title: originals[i].title || '',
        company: originals[i].company || '',
        location: originals[i].location || '',
      });
    }
  }
}

if (newJobs.length === 0) {
  return [{ json: { _dedupSkipped: true, _dedupQuery: '' } }];
}

// Get existing jobs from the preceding Postgres fetch node
const existingRows = $('Dedup: Fetch Recent').all();
const existingJobs = existingRows
  .filter(r => r.json.id != null)
  .map(r => ({
    id: r.json.id,
    title: r.json.title || '',
    company: r.json.company || '',
    location: r.json.location || '',
  }));

if (existingJobs.length === 0) {
  return [{ json: { _dedupSkipped: true, _dedupQuery: '' } }];
}

// Filter out existing jobs that are in the new batch (no self-comparison)
const newIds = new Set(newJobs.map(j => j.id));
const filteredExisting = existingJobs.filter(j => !newIds.has(j.id));

if (filteredExisting.length === 0) {
  return [{ json: { _dedupSkipped: true, _dedupQuery: '' } }];
}

// Write temp file for dedup_semantic.py
fs.mkdirSync(tmpDir, { recursive: true });
const tmpPath = tmpDir + '/n8n_dedup_' + Date.now() + '.json';
fs.writeFileSync(tmpPath, JSON.stringify({
  new_jobs: newJobs,
  existing_jobs: filteredExisting,
}), 'utf-8');

return [{ json: { _dedupTmpPath: tmpPath } }];

// Parse dedup_semantic.py output and build UPDATE queries
const table = $env.JOBS_FUNNEL_TABLE;
const stdout = $input.first().json.stdout || '[]';
try {
  const pairs = JSON.parse(stdout);
  if (!Array.isArray(pairs) || pairs.length === 0) {
    return [{ json: { _dedupQuery: '' } }];
  }
  return pairs.map(p => ({
    json: {
      _dedupQuery: `UPDATE ${table} SET possible_duplicate_of = ${Number(p.existing_id)} WHERE id = ${Number(p.new_id)} AND possible_duplicate_of IS NULL`
    }
  }));
} catch (e) {
  return [{ json: { _dedupQuery: '' } }];
}

